/**\n * Row-Level Security (RLS) Implementation Guide\n *\n * Adds defense-in-depth: even if API authorization is bypassed,\n * database-level RLS prevents unauthorized data access.\n *\n * Status: Ready for deployment via Supabase SQL editor or migration tools\n *\n * Installation:\n * 1. Log into Supabase dashboard\n * 2. Go to SQL Editor\n * 3. Run the migrations below (in order)\n * 4. Verify with SELECT statements in comments\n */\n\n-- ──────────────────────────────────────────────────────────────────────────────\n-- RLS POLICIES FOR CAMPAIGNS TABLE\n-- ──────────────────────────────────────────────────────────────────────────────\n\nCREATE POLICY campaigns_select_own_company ON campaigns\nFOR SELECT\nUSING (\n  -- Allow select if user's company_id matches, OR if user is super_admin\n  auth.uid() IN (\n    SELECT user_id FROM user_company_roles\n    WHERE company_id = campaigns.company_id\n      AND status = 'active'\n  )\n  OR\n  -- Super admin bypass (optional, based on your rbac service)\n  auth.uid() IN (\n    SELECT user_id FROM user_company_roles\n    WHERE role = 'super_admin'\n      AND status = 'active'\n  )\n);\n\nCREATE POLICY campaigns_insert_only_admins ON campaigns\nFOR INSERT\nWITH CHECK (\n  -- Only allow insert if user is company admin for this company\n  auth.uid() IN (\n    SELECT user_id FROM user_company_roles\n    WHERE company_id = campaigns.company_id\n      AND role IN ('company_admin', 'admin', 'super_admin')\n      AND status = 'active'\n  )\n);\n\nCREATE POLICY campaigns_update_only_admins ON campaigns\nFOR UPDATE\nUSING (\n  -- Can only update own company's campaigns\n  auth.uid() IN (\n    SELECT user_id FROM user_company_roles\n    WHERE company_id = campaigns.company_id\n      AND role IN ('company_admin', 'admin', 'super_admin')\n      AND status = 'active'\n  )\n)\nWITH CHECK (\n  -- Cannot change company_id\n  campaigns.company_id = old_campaigns.company_id\n);\n\nCREATE POLICY campaigns_delete_super_admin_only ON campaigns\nFOR DELETE\nUSING (\n  -- Only super admin can delete\n  auth.uid() IN (\n    SELECT user_id FROM user_company_roles\n    WHERE role = 'super_admin'\n      AND status = 'active'\n  )\n);\n\nALTER TABLE campaigns ENABLE ROW LEVEL SECURITY;\n\n-- Verification query (should show only campaigns for the user's company)\n-- SELECT id, name, company_id FROM campaigns;\n\n\n-- ──────────────────────────────────────────────────────────────────────────────\n-- RLS POLICIES FOR PUBLISHED_CONTENT TABLE\n-- ──────────────────────────────────────────────────────────────────────────────\n\nCREATE POLICY published_content_select_own_company ON published_content\nFOR SELECT\nUSING (\n  -- User can select if they have access to the campaign's company\n  campaign_id IN (\n    SELECT id FROM campaigns\n    WHERE company_id IN (\n      SELECT company_id FROM user_company_roles\n      WHERE user_id = auth.uid()\n        AND status = 'active'\n    )\n  )\n);\n\nCREATE POLICY published_content_insert_admins ON published_content\nFOR INSERT\nWITH CHECK (\n  -- Only admins of the campaign's company can insert\n  campaign_id IN (\n    SELECT id FROM campaigns\n    WHERE company_id IN (\n      SELECT company_id FROM user_company_roles\n      WHERE user_id = auth.uid()\n        AND role IN ('company_admin', 'admin', 'super_admin')\n        AND status = 'active'\n    )\n  )\n);\n\nALTER TABLE published_content ENABLE ROW LEVEL SECURITY;\n\n\n-- ──────────────────────────────────────────────────────────────────────────────\n-- RLS POLICIES FOR AUDIT_LOGS TABLE (Read-only)\n-- ──────────────────────────────────────────────────────────────────────────────\n\nCREATE POLICY audit_logs_select_own_company ON audit_logs\nFOR SELECT\nUSING (\n  -- Users can only see audit logs for their own company\n  company_id IN (\n    SELECT company_id FROM user_company_roles\n    WHERE user_id = auth.uid()\n      AND status = 'active'\n  )\n);\n\nCREATE POLICY audit_logs_insert_internal_only ON audit_logs\nFOR INSERT\nWITH CHECK (\n  -- Only application (via service role) can insert, not regular users\n  false  -- Always prevent direct user insert via RLS\n);\n\nCREATE POLICY audit_logs_delete_never ON audit_logs\nFOR DELETE\nUSING (false);  -- Never allow deletion\n\nALTER TABLE audit_logs ENABLE ROW LEVEL SECURITY;\n\n\n-- ──────────────────────────────────────────────────────────────────────────────\n-- VERIFICATION QUERIES\n-- Run these after enabling RLS to test\n-- ──────────────────────────────────────────────────────────────────────────────\n\n/*\nTEST 1: Verify campaigns_select_own_company policy\n--------\nNote: Replace 'test_user_id' with an actual user UUID\n\nSET LOCAL \"request.jwt.claims\" = jsonb_object_agg(pretty_key, pretty_value)\nFROM (\n  SELECT 'sub'::text as pretty_key, 'test_user_id'::text as pretty_value\n);\n\nSELECT id, name, company_id FROM campaigns;\n-- Expected: Only campaigns where user has active role in company_id\n\n\nTEST 2: Verify audit_logs read access\n--------\nSELECT id, operation, table_name, company_id FROM audit_logs LIMIT 5;\n-- Expected: Only audit logs from user's company\n\n\nTEST 3: Verify super_admin bypass\n--------\nFor user with super_admin role:\nSELECT COUNT(*) FROM campaigns;\n-- Expected: All campaigns (no filtering)\n*/\n\n\n-- ──────────────────────────────────────────────────────────────────────────────\n-- NOTES ON RLS WITH SERVICE ROLE\n-- ──────────────────────────────────────────────────────────────────────────────\n\n/*\n⚠️  IMPORTANT: RLS policies do NOT apply when using the service role key\n   (SUPABASE_SERVICE_ROLE_KEY). This is intentional for backend operations.\n\nBecause our supabaseClient uses the service role key:\n- RLS polices below provide DEFENSE-IN-DEPTH for frontend access\n- They also protect against \"privilege escalation\" if auth token is compromised\n- Backend API routes (using service role) bypass RLS and rely on enforceCompanyAccess()\n\nTo enable RLS protection for backend:\n1. Create separate Supabase clients for frontend vs backend\n2. Use anon key (client) with RLS + service role (admin) without RLS separately\n3. Or: Implement custom policy checks before all service role queries\n\nFor now, frontend clients SHOULD use anon key, not service role key.\nBackend API routes that expose to frontend should validate context with enforceCompanyAccess().\n*/\n"